<!DOCTYPE html>
<html lang="pt-BR">
<head> <meta charset="UTF-8"> <title>Relatório - BarberFlow</title> <style> body { font-family: Arial, sans-serif; font-size: 12px; color: #333; } .header { text-align: center; border-bottom: 2px solid #333; padding-bottom: 10px; margin-bottom: 20px; } .header h1 { margin: 0; font-size: 24px; color: #0d6efd; } .header p { margin: 5px 0 0 0; color: #666; } table { width: 100%; border-collapse: collapse; margin-bottom: 20px; } th, td { border: 1px solid #ddd; padding: 8px; text-align: left; } th { background-color: #f8f9fa; font-weight: bold; } .text-end { text-align: right; } .text-center { text-align: center; } .text-success { color: #198754; } .text-danger { color: #dc3545; } .fw-bold { font-weight: bold; } .footer { margin-top: 30px; text-align: center; font-size: 10px; color: #999; } </style>
</head>
<body> <div class="header"> <h1>BarberFlow - Relatório Administrativo</h1> <p> Período: {{ \Carbon\Carbon::parse($request->start_date)->format('d/m/Y') }} a {{ \Carbon\Carbon::parse($request->end_date)->format('d/m/Y') }} <br> Tipo: @if($type == 'appointments') Agendamentos @elseif($type == 'finance') Financeiro @elseif($type == 'services') Desempenho de Serviços @elseif($type == 'barbers') Desempenho de Barbeiros @endif </p> </div> @if(count($data) == 0) <p class="text-center">Nenhum dado encontrado para o período selecionado.</p> @else <table> @if($type == 'appointments') <thead> <tr> <th>Data/Hora</th> <th>Cliente</th> <th>Barbeiro</th> <th>Serviço</th> <th>Status</th> </tr> </thead> <tbody> @foreach($data as $row) <tr> <td>{{ \Carbon\Carbon::parse($row->data)->format('d/m/Y') }} às {{ \Carbon\Carbon::parse($row->hora)->format('H:i') }}</td> <td>{{ $row->cliente_nome }}</td> <td>{{ $row->barber->nome ?? 'N/D' }}</td> <td>{{ $row->service->nome ?? 'N/D' }} (R$ {{ number_format($row->service->valor ?? 0, 2, ',', '.') }})</td> <td> @if($row->status == 'agendado') Agendado @elseif($row->status == 'em_atendimento') Em Atendimento @elseif($row->status == 'concluido') Concluído @elseif($row->status == 'cancelado') Cancelado @else Não Compareceu @endif </td> </tr> @endforeach </tbody> @elseif($type == 'finance') <thead> <tr> <th>Data</th> <th>Tipo</th> <th>Categoria</th> <th>Descrição</th> <th class="text-end">Valor (R$)</th> </tr> </thead> <tbody> @php $totalReceita = 0; $totalDespesa = 0; @endphp @foreach($data as $row) @php if($row->tipo == 'entrada') $totalReceita += $row->valor; else $totalDespesa += $row->valor; @endphp <tr> <td>{{ \Carbon\Carbon::parse($row->data)->format('d/m/Y') }}</td> <td>{{ $row->tipo == 'entrada' ? 'Receita' : 'Despesa' }}</td> <td>{{ $row->categoria }}</td> <td>{{ $row->descricao }}</td> <td class="text-end fw-bold {{ $row->tipo == 'entrada' ? 'text-success' : 'text-danger' }}"> R$ {{ number_format($row->valor, 2, ',', '.') }} </td> </tr> @endforeach </tbody> <tfoot> <tr> <td colspan="4" class="text-end fw-bold">Balanço do Período:</td> <td class="text-end fw-bold {{ ($totalReceita - $totalDespesa) >= 0 ? 'text-success' : 'text-danger' }}"> R$ {{ number_format($totalReceita - $totalDespesa, 2, ',', '.') }} </td> </tr> </tfoot> @elseif($type == 'services') <thead> <tr> <th>#</th> <th>Serviço</th> <th class="text-center">Quantidade Vendida</th> <th class="text-end">Faturamento Total</th> </tr> </thead> <tbody> @foreach($data as $index => $row) <tr> <td>{{ $index + 1 }}</td> <td class="fw-bold">{{ $row['nome'] }}</td> <td class="text-center">{{ $row['qtd'] }}x</td> <td class="text-end fw-bold text-success">R$ {{ number_format($row['faturamento'], 2, ',', '.') }}</td> </tr> @endforeach </tbody> @elseif($type == 'barbers') <thead> <tr> <th>#</th> <th>Barbeiro</th> <th class="text-center">Atendimentos Concluídos</th> <th class="text-end">Faturamento Gerado</th> </tr> </thead> <tbody> @foreach($data as $index => $row) <tr> <td>{{ $index + 1 }}</td> <td class="fw-bold">{{ $row['nome'] }}</td> <td class="text-center">{{ $row['qtd'] }} atendimentos</td> <td class="text-end fw-bold text-success">R$ {{ number_format($row['faturamento'], 2, ',', '.') }}</td> </tr> @endforeach </tbody> @endif </table> @endif <div class="footer"> Documento gerado pelo sistema BarberFlow em {{ date('d/m/Y H:i:s') }} </div>
</body>
</html>

